// Time:  O(n + k^2)
// Space: O(n + k)

// dp, prefix sum
class Solution {
public:
    int possibleStringCount(string word, int k) {
        static const int MOD = 1e9 + 7;

        vector<int> cnt = {0};
        for (int i = 0; i < size(word); ++i) {
            ++cnt.back();
            if (i + 1 == size(word) || word[i + 1] != word[i]) {
                cnt.emplace_back(0);
            }
        }
        cnt.pop_back();
        int result = accumulate(cbegin(cnt), cend(cnt), 1ll, [](const auto& accu, const auto& x) {
            return (accu * x) % MOD;
        });
        if (k <= size(cnt)) {
            return result;
        }
        vector<int> dp(k - size(cnt));
        dp[0] = 1;
        for (const auto& l : cnt) {
            for (int i = 0; i + 1 < size(dp); ++i) {
                dp[i + 1] = (dp[i + 1] + dp[i]) % MOD;
            }
            for (int i = size(dp) - 1; i >= l; --i) {
                dp[i] = ((dp[i] - dp[i - l]) % MOD + MOD) % MOD;
            }
        }
        return ((result - accumulate(cbegin(dp), cend(dp), 0, [](const auto& accu, const auto& x) {
            return (accu + x) % MOD;
        })) % MOD + MOD) % MOD;
    }
};

# Time:  O(n + k^2)
# Space: O(n + k)

# dp, prefix sum
class Solution(object):
    def possibleStringCount(self, word, k):
        MOD = 10**9+7
        cnt = [0]
        for i in xrange(len(word)):
            cnt[-1] += 1
            if i+1 == len(word) or word[i+1] != word[i]:
                cnt.append(0)
        cnt.pop()
        result = reduce(lambda accu, x: accu*x%MOD, cnt, 1)
        if k <= len(cnt):
            return result
        dp = [0]*(k-len(cnt))
        dp[0] = 1
        for l in cnt:
            for i in xrange(len(dp)-1):
                dp[i+1] = (dp[i+1]+dp[i])%MOD
            for i in reversed(xrange(l, len(dp))):
                dp[i] = (dp[i]-dp[i-l])%MOD
        return reduce(lambda accu, x: (accu-x)%MOD, dp, result)
